namespace sv_b7d1c56d19644abba2b3ee6f49a87a15.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@using sv_b7d1c56d19644abba2b3ee6f49a87a15.Services

<div class="card product-card h-100" @onclick="OnCardClicked" style="cursor: pointer;">
    <div class="product-image-placeholder d-flex align-items-center justify-content-center bg-light" style="height: 180px;">
        <span class="text-muted">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <p class="mb-1">@GetStarRating(Product.Rating)</p>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-sm btn-success mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="OnAddToCartClicked"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task OnCardClicked()
    {
        await OnProductSelected.InvokeAsync(Product);
    }

    private async Task OnAddToCartClicked()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }

    private static string GetStarRating(double rating)
    {
        int filled = (int)Math.Round(rating);
        int empty = 5 - filled;
        return new string('★', filled) + new string('☆', empty);
    }
}

@page "/catalog"
@using sv_b7d1c56d19644abba2b3ee6f49a87a15.Services
@inject IProductService ProductService
@inject NavigationManager Navigation
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="RetryAsync">Retry</button>
    </div>
}
else
{
    <div class="row">
        @* ── Left Sidebar: Filters ── *@
        <div class="col-md-3">
            <div class="card">
                <div class="card-header fw-bold">Filters</div>
                <div class="card-body">
                    @* Category checkboxes *@
                    <h6>Category</h6>
                    @if (_categories is null)
                    {
                        <p class="text-muted small">Loading categories…</p>
                    }
                    else
                    {
                        @foreach (var category in _categories)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                                       checked="@_selectedCategories.Contains(category)"
                                       @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                                <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                            </div>
                        }
                    }

                    <hr />

                    @* Price range *@
                    <h6>Price Range</h6>
                    <div class="mb-2">
                        <label class="form-label small">Min Price</label>
                        <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                               @bind="_minPrice" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label small">Max Price</label>
                        <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                               @bind="_maxPrice" />
                    </div>

                    <hr />

                    @* In Stock Only *@
                    <div class="form-check mb-3">
                        <input class="form-check-input" type="checkbox" id="inStockOnly"
                               @bind="_inStockOnly" />
                        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                    </div>

                    @* Action buttons *@
                    <div class="d-grid gap-2">
                        <button class="btn btn-primary btn-sm" @onclick="ApplyFiltersAsync" disabled="@_loading">
                            Apply Filters
                        </button>
                        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFiltersAsync" disabled="@_loading">
                            Clear Filters
                        </button>
                    </div>
                </div>
            </div>
        </div>

        @* ── Main Content Area ── *@
        <div class="col-md-9">
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3">
                <div>
                    <label class="form-label small mb-0 me-1">Sort by:</label>
                    <select class="form-select form-select-sm d-inline-block w-auto"
                            @onchange="OnSortChangedAsync">
                        @foreach (var option in _sortOptions)
                        {
                            <option value="@option.Value" selected="@(option.Value == _sortBy)">@option.Label</option>
                        }
                    </select>
                </div>
                <div class="text-muted small">
                    @if (_result is not null && _result.TotalCount > 0)
                    {
                        var start = (_currentPage - 1) * PageSize + 1;
                        var end = Math.Min(_currentPage * PageSize, _result.TotalCount);
                        <span>Showing @start–@end of @_result.TotalCount products</span>
                    }
                </div>
            </div>

            @* Content states *@
            @if (_loading)
            {
                <div class="text-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading…</span>
                    </div>
                    <p class="text-muted mt-2">Loading products…</p>
                </div>
            }
            else if (_result is null || _result.Items.Count == 0)
            {
                <div class="text-center py-5">
                    <p class="text-muted fs-5">No products found matching your criteria.</p>
                    <button class="btn btn-outline-primary btn-sm" @onclick="ClearFiltersAsync">Clear Filters</button>
                </div>
            }
            else
            {
                @* Product grid *@
                <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
                    @foreach (var product in _result.Items)
                    {
                        <div class="col">
                            <ProductCard Product="product"
                                         OnProductSelected="OnProductSelected"
                                         OnAddToCart="OnAddToCart" />
                        </div>
                    }
                </div>

                @* Pagination *@
                @if (TotalPages > 1)
                {
                    <nav class="mt-4" aria-label="Product pagination">
                        <ul class="pagination justify-content-center">
                            <li class="page-item @(_currentPage == 1 ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPageAsync(_currentPage - 1)"
                                        disabled="@(_currentPage == 1)">
                                    Previous
                                </button>
                            </li>
                            @for (int i = 1; i <= TotalPages; i++)
                            {
                                var pageNum = i;
                                <li class="page-item @(pageNum == _currentPage ? "active" : "")">
                                    <button class="page-link" @onclick="() => GoToPageAsync(pageNum)">
                                        @pageNum
                                    </button>
                                </li>
                            }
                            <li class="page-item @(_currentPage == TotalPages ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPageAsync(_currentPage + 1)"
                                        disabled="@(_currentPage == TotalPages)">
                                    Next
                                </button>
                            </li>
                        </ul>
                    </nav>
                }
            }
        </div>
    </div>
}

@code {
    private const int PageSize = 12;

    private List<string>? _categories;
    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;
    private string _sortBy = "price_asc";
    private int _currentPage = 1;

    private PagedResult<Product>? _result;
    private bool _loading = true;
    private string? _error;

    private int TotalPages => _result is null || _result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / PageSize);

    private static readonly (string Label, string Value)[] _sortOptions =
    [
        ("Price: Low to High", "price_asc"),
        ("Price: High to Low", "price_desc"),
        ("Name: A-Z", "name_asc"),
        ("Rating: Highest", "rating_desc"),
    ];

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _loading = true;
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = SearchProductsAsync();
            _categories = await categoriesTask;
            await searchTask;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SearchProductsAsync()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );

        _result = await ProductService.SearchAsync(filter, _sortBy, _currentPage, PageSize);
    }

    private async Task ApplyFiltersAsync()
    {
        _currentPage = 1;
        await LoadAsync();
    }

    private async Task ClearFiltersAsync()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _sortBy = "price_asc";
        _currentPage = 1;
        await LoadAsync();
    }

    private async Task OnSortChangedAsync(ChangeEventArgs e)
    {
        _sortBy = e.Value?.ToString() ?? "price_asc";
        _currentPage = 1;
        await LoadAsync();
    }

    private async Task GoToPageAsync(int page)
    {
        if (page < 1 || page > TotalPages) return;
        _currentPage = page;
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        try
        {
            _loading = true;
            _error = null;
            await SearchProductsAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task RetryAsync()
    {
        _error = null;
        if (_categories is null)
        {
            await OnInitializedAsync();
        }
        else
        {
            await LoadAsync();
        }
    }

    private void ToggleCategory(string category, bool selected)
    {
        if (selected)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private void OnProductSelected(Product product)
    {
        Navigation.NavigateTo($"/catalog/{product.Id}");
    }

    private Task OnAddToCart(Product product)
    {
        // Placeholder for add-to-cart logic
        return Task.CompletedTask;
    }
}

