@using sv_b7d1c56d19644abba2b3ee6f49a87a15.Services
@inject IProductService ProductService
@inject NavigationManager Navigation
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="RetryAsync">Retry</button>
    </div>
}
else
{
    <div class="row">
        @* ── Left Sidebar: Filters ── *@
        <div class="col-md-3">
            <div class="card">
                <div class="card-header fw-bold">Filters</div>
                <div class="card-body">
                    @* Category checkboxes *@
                    <h6>Category</h6>
                    @if (_categories is null)
                    {
                        <p class="text-muted small">Loading categories…</p>
                    }
                    else
                    {
                        @foreach (var category in _categories)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                                       checked="@_selectedCategories.Contains(category)"
                                       @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                                <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                            </div>
                        }
                    }

                    <hr />

                    @* Price range *@
                    <h6>Price Range</h6>
                    <div class="mb-2">
                        <label class="form-label small">Min Price</label>
                        <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                               @bind="_minPrice" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label small">Max Price</label>
                        <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                               @bind="_maxPrice" />
                    </div>

                    <hr />

                    @* In Stock Only *@
                    <div class="form-check mb-3">
                        <input class="form-check-input" type="checkbox" id="inStockOnly"
                               @bind="_inStockOnly" />
                        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                    </div>

                    @* Action buttons *@
                    <div class="d-grid gap-2">
                        <button class="btn btn-primary btn-sm" @onclick="ApplyFiltersAsync" disabled="@_loading">
                            Apply Filters
                        </button>
                        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFiltersAsync" disabled="@_loading">
                            Clear Filters
                        </button>
                    </div>
                </div>
            </div>
        </div>

        @* ── Main Content Area ── *@
        <div class="col-md-9">
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3">
                <div>
                    <label class="form-label small mb-0 me-1">Sort by:</label>
                    <select class="form-select form-select-sm d-inline-block w-auto"
                            @onchange="OnSortChangedAsync">
                        @foreach (var option in _sortOptions)
                        {
                            <option value="@option.Value" selected="@(option.Value == _sortBy)">@option.Label</option>
                        }
                    </select>
                </div>
                <div class="text-muted small">
                    @if (_result is not null && _result.TotalCount > 0)
                    {
                        var start = (_currentPage - 1) * PageSize + 1;
                        var end = Math.Min(_currentPage * PageSize, _result.TotalCount);
                        <span>Showing @start–@end of @_result.TotalCount products</span>
                    }
                </div>
            </div>

            @* Content states *@
            @if (_loading)
            {
                <div class="text-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading…</span>
                    </div>
                    <p class="text-muted mt-2">Loading products…</p>
                </div>
            }
            else if (_result is null || _result.Items.Count == 0)
            {
                <div class="text-center py-5">
                    <p class="text-muted fs-5">No products found matching your criteria.</p>
                    <button class="btn btn-outline-primary btn-sm" @onclick="ClearFiltersAsync">Clear Filters</button>
                </div>
            }
            else
            {
                @* Product grid *@
                <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
                    @foreach (var product in _result.Items)
                    {
                        <div class="col">
                            <ProductCard Product="product"
                                         OnProductSelected="OnProductSelected"
                                         OnAddToCart="OnAddToCart" />
                        </div>
                    }
                </div>

                @* Pagination *@
                @if (TotalPages > 1)
                {
                    <nav class="mt-4" aria-label="Product pagination">
                        <ul class="pagination justify-content-center">
                            <li class="page-item @(_currentPage == 1 ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPageAsync(_currentPage - 1)"
                                        disabled="@(_currentPage == 1)">
                                    Previous
                                </button>
                            </li>
                            @for (int i = 1; i <= TotalPages; i++)
                            {
                                var pageNum = i;
                                <li class="page-item @(pageNum == _currentPage ? "active" : "")">
                                    <button class="page-link" @onclick="() => GoToPageAsync(pageNum)">
                                        @pageNum
                                    </button>
                                </li>
                            }
                            <li class="page-item @(_currentPage == TotalPages ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPageAsync(_currentPage + 1)"
                                        disabled="@(_currentPage == TotalPages)">
                                    Next
                                </button>
                            </li>
                        </ul>
                    </nav>
                }
            }
        </div>
    </div>
}

