+                <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
+                    @foreach (var product in _result.Items)
+                    {
+                        <div class="col">
+                            <ProductCard Product="product"
+                                         OnProductSelected="OnProductSelected"
+                                         OnAddToCart="OnAddToCart" />
+                        </div>
+                    }
+                </div>
+
+                @* Pagination *@
+                @if (TotalPages > 1)
+                {
+                    <nav class="mt-4" aria-label="Product pagination">
+                        <ul class="pagination justify-content-center">
+                            <li class="page-item @(_currentPage == 1 ? "disabled" : "")">
+                                <button class="page-link" @onclick="() => GoToPageAsync(_currentPage - 1)"
+                                        disabled="@(_currentPage == 1)">
+                                    Previous
+                                </button>
+                            </li>
+                            @for (int i = 1; i <= TotalPages; i++)
+                            {
+                                var pageNum = i;
+                                <li class="page-item @(pageNum == _currentPage ? "active" : "")">
+                                    <button class="page-link" @onclick="() => GoToPageAsync(pageNum)">
+                                        @pageNum
+                                    </button>
+                                </li>
+                            }
+                            <li class="page-item @(_currentPage == TotalPages ? "disabled" : "")">
+                                <button class="page-link" @onclick="() => GoToPageAsync(_currentPage + 1)"
+                                        disabled="@(_currentPage == TotalPages)">
+                                    Next
+                                </button>
+                            </li>
+                        </ul>
+                    </nav>
+                }
+            }
+        </div>
+    </div>
+}
