+@code {
+    private const int PageSize = 12;
+
+    private List<string>? _categories;
+    private HashSet<string> _selectedCategories = new();
+    private decimal? _minPrice;
+    private decimal? _maxPrice;
+    private bool _inStockOnly;
+    private string _sortBy = "price_asc";
+    private int _currentPage = 1;
+
+    private PagedResult<Product>? _result;
+    private bool _loading = true;
+    private string? _error;
+
+    private int TotalPages => _result is null || _result.TotalCount == 0
+        ? 1
+        : (int)Math.Ceiling((double)_result.TotalCount / PageSize);
+
+    private static readonly (string Label, string Value)[] _sortOptions =
+    [
+        ("Price: Low to High", "price_asc"),
+        ("Price: High to Low", "price_desc"),
+        ("Name: A-Z", "name_asc"),
+        ("Rating: Highest", "rating_desc"),
+    ];
+
+    protected override async Task OnInitializedAsync()
+    {
+        try
+        {
+            _loading = true;
+            var categoriesTask = ProductService.GetCategoriesAsync();
+            var searchTask = SearchProductsAsync();
+            _categories = await categoriesTask;
+            await searchTask;
+        }
+        catch (Exception ex)
+        {
+            _error = ex.Message;
+        }
+        finally
+        {
+            _loading = false;
+        }
+    }
+
+    private async Task SearchProductsAsync()
+    {
+        var filter = new ProductFilter(
+            Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
+            MinPrice: _minPrice,
+            MaxPrice: _maxPrice,
+            InStockOnly: _inStockOnly
+        );
+
+        _result = await ProductService.SearchAsync(filter, _sortBy, _currentPage, PageSize);
+    }
+
+    private async Task ApplyFiltersAsync()
+    {
+        _currentPage = 1;
+        await LoadAsync();
+    }
+
+    private async Task ClearFiltersAsync()
+    {
+        _selectedCategories.Clear();
+        _minPrice = null;
+        _maxPrice = null;
+        _inStockOnly = false;
+        _sortBy = "price_asc";
+        _currentPage = 1;
+        await LoadAsync();
+    }
+
+    private async Task OnSortChangedAsync(ChangeEventArgs e)
+    {
+        _sortBy = e.Value?.ToString() ?? "price_asc";
+        _currentPage = 1;
+        await LoadAsync();
+    }
+
+    private async Task GoToPageAsync(int page)
+    {
+        if (page < 1 || page > TotalPages) return;
+        _currentPage = page;
+        await LoadAsync();
+    }
+
+    private async Task LoadAsync()
+    {
+        try
+        {
+            _loading = true;
+            _error = null;
+            await SearchProductsAsync();
+        }
+        catch (Exception ex)
+        {
+            _error = ex.Message;
+        }
+        finally
+        {
+            _loading = false;
+        }
+    }
+
+    private async Task RetryAsync()
+    {
+        _error = null;
+        if (_categories is null)
+        {
+            await OnInitializedAsync();
+        }
+        else
+        {
+            await LoadAsync();
+        }
+    }
+
+    private void ToggleCategory(string category, bool selected)
+    {
+        if (selected)
+            _selectedCategories.Add(category);
+        else
+            _selectedCategories.Remove(category);
+    }
+
+    private void OnProductSelected(Product product)
+    {
+        Navigation.NavigateTo($"/catalog/{product.Id}");
+    }
+
+    private Task OnAddToCart(Product product)
+    {
+        // Placeholder for add-to-cart logic
+        return Task.CompletedTask;
+    }
+}
